<script>
// Turnstile verification tracker
var turnstileVerified = false;

// Callback when Turnstile is successfully completed
function onTurnstileSuccess(token) {
  turnstileVerified = true;
  document.getElementById('captchaError').style.display = 'none';
}

// Form submission with Turnstile validation
document.getElementById('hostingForm').addEventListener('submit', function(e){
  e.preventDefault();
  
  // Check if Turnstile is completed
  if(!turnstileVerified) {
    // Show error message
    document.getElementById('captchaError').style.display = 'block';
    
    // Scroll to captcha
    document.querySelector('.cf-turnstile').scrollIntoView({ behavior: 'smooth', block: 'center' });
    
    // Shake effect for captcha box
    var captchaBox = document.querySelector('.cf-turnstile');
    captchaBox.style.animation = 'shake 0.5s';
    setTimeout(function(){ captchaBox.style.animation = ''; }, 500);
    
    return false;
  }
  
  // Hide error if captcha is verified
  document.getElementById('captchaError').style.display = 'none';
  
  // Disable submit button to prevent double submission
  var submitBtn = document.getElementById('submitBtn');
  submitBtn.disabled = true;
  submitBtn.style.opacity = '0.6';
  submitBtn.style.cursor = 'not-allowed';
  submitBtn.innerHTML = '⏳ Submitting...';
  
  // Submit form via AJAX
  var formData = new FormData(this);
  
  fetch(this.action, {
    method: 'POST',
    body: formData
  })
  .then(function(){
    // Show thank you message
    document.getElementById('hostingForm').style.display='none';
    document.getElementById('thanksMsg').style.display='block';
    
    // Reset verification
    turnstileVerified = false;
  })
  .catch(function(error){
    console.error('Error:', error);
    alert('Something went wrong. Please try again.');
    submitBtn.disabled = false;
    submitBtn.style.opacity = '1';
    submitBtn.style.cursor = 'pointer';
    submitBtn.innerHTML = 'Submit Hosting Request';
    turnstileVerified = false;
  });
});

// Add shake animation
var style = document.createElement('style');
style.innerHTML = `
  @keyframes shake {
    0%, 100% { transform: translateX(0); }
    10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
    20%, 40%, 60%, 80% { transform: translateX(5px); }
  }
`;
document.head.appendChild(style);
</script>
  

 

